import React, { useState, useCallback, useRef } from 'react'
import { useDropzone } from 'react-dropzone'
import { SelfieSegmentation } from '@mediapipe/selfie_segmentation'

function App() {
  const [images, setImages] = useState([])
  const [processing, setProcessing] = useState(false)
  const [selectedBg, setSelectedBg] = useState('transparent')
  const selfieSegmentationRef = useRef(null)

  // Initialize MediaPipe
  const initSelfieSegmentation = useCallback(async () => {
    if (selfieSegmentationRef.current) return selfieSegmentationRef.current

    const selfieSegmentation = new SelfieSegmentation({
      locateFile: (file) => {
        return `https://cdn.jsdelivr.net/npm/@mediapipe/selfie_segmentation/${file}`
      }
    })

    selfieSegmentation.setOptions({
      modelSelection: 1,
      selfieMode: false
    })

    selfieSegmentationRef.current = selfieSegmentation
    return selfieSegmentation
  }, [])

  // Handle file drop
  const onDrop = useCallback((acceptedFiles) => {
    const newImages = acceptedFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      name: file.name,
      preview: URL.createObjectURL(file),
      status: 'pending'
    }))
    setImages(prev => [...prev, ...newImages])
  }, [])

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'image/*': ['.jpg', '.jpeg', '.png', '.webp']
    },
    maxSize: 10 * 1024 * 1024
  })

  // Remove image
  const removeImage = useCallback((id) => {
    setImages(prev => {
      const image = prev.find(img => img.id === id)
      if (image) {
        URL.revokeObjectURL(image.preview)
        if (image.result) URL.revokeObjectURL(image.result)
      }
      return prev.filter(img => img.id !== id)
    })
  }, [])

  // Process single image
  const processImage = useCallback(async (id, backgroundColor = selectedBg) => {
    const image = images.find(img => img.id === id)
    if (!image) return

    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, status: 'processing' } : img
    ))

    try {
      const selfieSegmentation = await initSelfieSegmentation()
      
      const canvas = document.createElement('canvas')
      const ctx = canvas.getContext('2d')
      if (!ctx) throw new Error('Could not get canvas context')

      const img = new Image()
      img.src = image.preview
      await new Promise((resolve) => { img.onload = resolve })

      canvas.width = img.width
      canvas.height = img.height

      await new Promise((resolve, reject) => {
        selfieSegmentation.onResults((results) => {
          if (results.segmentationMask) {
            if (backgroundColor === 'transparent') {
              ctx.clearRect(0, 0, canvas.width, canvas.height)
            } else {
              ctx.fillStyle = backgroundColor
              ctx.fillRect(0, 0, canvas.width, canvas.height)
            }

            ctx.save()
            ctx.globalCompositeOperation = 'destination-in'
            ctx.drawImage(results.segmentationMask, 0, 0, canvas.width, canvas.height)
            ctx.restore()

            ctx.globalCompositeOperation = 'source-over'
            ctx.drawImage(img, 0, 0)
          }
          resolve()
        })

        selfieSegmentation.send({ image: img }).catch(reject)
      })

      const result = canvas.toDataURL('image/png')

      setImages(prev => prev.map(img => 
        img.id === id ? { ...img, status: 'done', result, backgroundColor } : img
      ))
    } catch (error) {
      console.error('Processing error:', error)
      setImages(prev => prev.map(img => 
        img.id === id ? { ...img, status: 'error' } : img
      ))
    }
  }, [images, initSelfieSegmentation, selectedBg])

  // Process all pending images
  const processAll = useCallback(async () => {
    setProcessing(true)
    const pendingImages = images.filter(img => img.status === 'pending')
    
    for (const image of pendingImages) {
      await processImage(image.id)
    }
    
    setProcessing(false)
  }, [images, processImage])

  // Download processed image
  const downloadImage = useCallback((id) => {
    const image = images.find(img => img.id === id)
    if (!image?.result) return

    const link = document.createElement('a')
    link.href = image.result
    link.download = `removed-bg-${image.name}`
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
  }, [images])

  // Background color options
  const bgOptions = [
    { value: 'transparent', label: '透明', color: 'bg-gray-100' },
    { value: '#ffffff', label: '白色', color: 'bg-white border' },
    { value: '#000000', label: '黑色', color: 'bg-black' },
    { value: '#ff0000', label: '红色', color: 'bg-red-500' },
    { value: '#00ff00', label: '绿色', color: 'bg-green-500' },
    { value: '#0000ff', label: '蓝色', color: 'bg-blue-500' },
  ]

  // Get status display
  const getStatusDisplay = (status) => {
    switch (status) {
      case 'pending': return { text: '待处理', color: 'bg-gray-100 text-gray-600' }
      case 'processing': return { text: '处理中...', color: 'bg-blue-100 text-blue-600' }
      case 'done': return { text: '已完成', color: 'bg-green-100 text-green-600' }
      case 'error': return { text: '失败', color: 'bg-red-100 text-red-600' }
      default: return { text: '未知', color: 'bg-gray-100 text-gray-600' }
    }
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm">
        <div className="max-w-6xl mx-auto px-4 py-6">
          <h1 className="text-2xl font-bold text-gray-900">🎨 AI 智能抠图工具</h1>
          <p className="text-gray-500 mt-1">上传图片，自动去除背景</p>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8">
        {/* Upload Area */}
        <div
          {...getRootProps()}
          className={`border-2 border-dashed rounded-xl p-12 text-center cursor-pointer transition-all duration-200 ${
            isDragActive 
              ? 'border-blue-500 bg-blue-50' 
              : 'border-gray-300 hover:border-gray-400 hover:bg-gray-50'
          }`}
        >
          <input {...getInputProps()} />
          <div className="text-6xl mb-4">📤</div>
          <p className="text-lg font-medium text-gray-900 mb-2">
            {isDragActive ? '松开以上传' : '拖拽图片到这里'}
          </p>
          <p className="text-sm text-gray-500">
            或点击选择文件，支持 JPG、PNG、WEBP
          </p>
          <p className="text-xs text-gray-400 mt-2">
            单张最大 10MB
          </p>
        </div>

        {/* Background Selection */}
        {images.length > 0 && (
          <div className="mt-8 bg-white rounded-xl shadow-sm border p-6">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">🎨 选择背景</h3>
            <div className="flex flex-wrap gap-3">
              {bgOptions.map((option) => (
                <button
                  key={option.value}
                  onClick={() => setSelectedBg(option.value)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg border transition-all ${
                    selectedBg === option.value
                      ? 'border-blue-500 bg-blue-50 text-blue-700'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <div className={`w-6 h-6 rounded ${option.color}`} />
                  <span className="text-sm">{option.label}</span>
                </button>
              ))}
            </div>
            
            <div className="mt-4 flex gap-3">
              <button
                onClick={processAll}
                disabled={processing || !images.some(img => img.status === 'pending')}
                className="px-6 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
              >
                {processing && <span className="animate-spin">⏳</span>}
                批量处理全部
              </button>
              <span className="text-sm text-gray-500 self-center">
                待处理: {images.filter(img => img.status === 'pending').length} 张
              </span>
            </div>
          </div>
        )}

        {/* Image Grid */}
        {images.length > 0 && (
          <div className="mt-8 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {images.map((image) => {
              const status = getStatusDisplay(image.status)
              return (
                <div key={image.id} className="bg-white rounded-xl shadow-sm border overflow-hidden">
                  {/* Image Preview */}
                  <div className="relative aspect-square bg-gray-100">
                    <img
                      src={image.result || image.preview}
                      alt={image.name}
                      className="w-full h-full object-contain"
                    />
                    {/* Status Badge */}
                    <div className={`absolute top-2 right-2 px-2 py-1 rounded-full text-xs font-medium ${status.color}`}>
                      {status.text}
                    </div>
                  </div>

                  {/* Image Info */}
                  <div className="p-4">
                    <p className="text-sm font-medium text-gray-900 truncate" title={image.name}>
                      {image.name}
                    </p>
                    
                    {/* Action Buttons */}
                    <div className="flex gap-2 mt-3">
                      {image.status === 'pending' && (
                        <button
                          onClick={() => processImage(image.id)}
                          disabled={processing}
                          className="flex-1 px-3 py-1.5 bg-blue-600 text-white text-sm rounded hover:bg-blue-700 disabled:opacity-50"
                        >
                          开始抠图
                        </button>
                      )}
                      
                      {image.status === 'done' && (
                        <>
                          <button
                            onClick={() => downloadImage(image.id)}
                            className="flex-1 px-3 py-1.5 bg-green-600 text-white text-sm rounded hover:bg-green-700"
                          >
                            下载
                          </button>
                          <button
                            onClick={() => processImage(image.id)}
                            className="px-3 py-1.5 bg-blue-100 text-blue-700 text-sm rounded hover:bg-blue-200"
                          >
                            重新处理
                          </button>
                        </>
                      )}
                      
                      <button
                        onClick={() => removeImage(image.id)}
                        className="px-3 py-1.5 bg-gray-100 text-gray-700 text-sm rounded hover:bg-gray-200"
                      >
                        删除
                      </button>
                    </div>
                  </div>
                </div>
              )
            })}
          </div>
        )}

        {/* Empty State */}
        {images.length === 0 && (
          <div className="mt-12 text-center py-16">
            <div className="text-6xl mb-4">🖼️</div>
            <h3 className="text-xl font-semibold text-gray-900 mb-2">
              还没有图片
            </h3>
            <p className="text-gray-500 max-w-md mx-auto">
              上传图片上方开始 AI 智能抠图
            </p>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t mt-16">
        <div className="max-w-6xl mx-auto px-4 py-6">
          <p className="text-center text-gray-500 text-sm">
            © 2026 AI 智能抠图工具 | Powered by MediaPipe
          </p>
        </div>
      </footer>
    </div>
  )
}

export default App
